#include<bits/stdc++.h>
using namespace std;
const int N = 1e7+5;
long long n,a[N],s[N],ans;
#define getchar()(p1==p2&&(p2=(p1=buf)+fread(buf,1,1<<21,stdin),p1==p2)?EOF:*p1++)
char buf[1<<21],*p1=buf,*p2=buf;
template <typename T>
inline void read(T& r) {
	r=0;bool w=0; char ch=getchar();
	while(ch<'0'||ch>'9') w=ch=='-'?1:0,ch=getchar();
	while(ch>='0'&&ch<='9') r=r*10+(ch^48), ch=getchar();
	r=w?-r:r;
}
inline void write(int r){
    if(r<0){putchar('-');r=-r;}
    if(r>9)write(r/10);
    putchar(r%10+'0');
}
int main(){
	//freopen("fenzu.in","r",stdin);
	//freopen("fenzu.out","w",stdout);
    read(n);
	for(int i=1;i<=n;i++){
        read(a[i]);
		if(a[i]==0){ans++;continue;}
		s[int(log2(a[i]&-a[i]))]|=a[i];
	}
	for(int i=0;i<60;i++)
		for(int j=i+1;j<60;j++)
			if(s[i]&s[j])s[j]|=s[i],s[i]=0;
	for(int i=0;i<60;i++)if(s[i])ans++;
	write(ans);
	return 0;
}
